templates.css_template:
.modern-lt-container {
    padding: 0;
    font-family: '{{FONT_FAMILY}}', sans-serif;
}
.modern-plate {
    background: linear-gradient(135deg, {{PRIMARY_COLOR}}, {{SECONDARY_COLOR}});
    padding: 24px 48px;
    border-radius: 12px;
    color: white;
    display: inline-block;
    box-shadow: 0 20px 40px rgba(0,0,0,0.4);
    opacity: 0;
    transform: {{ANIMATION_IN_TRANSFORM}};
    transition: all {{ANIMATION_DURATION}}s {{ANIMATION_EASE}};
    border: 1px solid rgba(255,255,255,0.1);
    backdrop-filter: blur(10px);
}
.modern-title {
    margin: 0;
    font-size: {{TITLE_SIZE}}px;
    font-weight: {{TITLE_WEIGHT}};
    text-transform: {{TITLE_TRANSFORM}};
    letter-spacing: 1px;
    text-shadow: 2px 2px 4px rgba(0,0,0,0.3);
}
.modern-plate {
    position: relative;
    overflow: hidden;
}
.modern-plate::after {
    content: '';
    position: absolute;
    top: 0;
    left: -100%;
    width: 50%;
    height: 100%;
    background: linear-gradient(to right, rgba(255,255,255,0) 0%, rgba(255,255,255,0.3) 50%, rgba(255,255,255,0) 100%);
    transform: skewX(-20deg);
    animation: shine 6s infinite;
}
@keyframes shine {
    0% { left: -100%; }
    20% { left: 200%; }
    100% { left: 200%; }
}

templates.js_template:
(() => {
    const root = document.getElementById("{{ID}}");
    const plate = root.querySelector('.modern-plate');

    root.__slt_show = () => {
        const delay = "{{ANIMATION_DELAY}}" || 0;
        const el = root.querySelector('[class*="container"], [class*="plate"], [class*="box"], [class*="bar"], [class*="panel"]') || root.children[0];
        if(el) el.style.transitionDelay = `${delay}s`;
        plate.style.opacity = '1';
        plate.style.transform = "{{ANIMATION_IDENTITY}}";
    };

    root.__slt_hide = () => {
        const el = root.querySelector('[class*="container"], [class*="plate"], [class*="box"], [class*="bar"], [class*="panel"]') || root.children[0];
        if(el) el.style.transitionDelay = '{{ANIMATION_OUT_DELAY}}s';
        if (typeof plate !== 'undefined' && plate) {
            plate.style.transition = "all {{ANIMATION_OUT_DURATION}}s {{ANIMATION_OUT_EASE}} {{ANIMATION_OUT_DELAY}}s";
            plate.style.opacity = '0';
            plate.style.transform = "{{ANIMATION_OUT_TRANSFORM}}";
        }
    };
})();

(() => { 
    const root = document.getElementById("{{ID}}"); 
    const container = root.querySelector('.modern-ticker'); 
    const tickerTrack = root.querySelector('.ticker-track'); 

    root.__slt_show = () => { 
        const delay = "{{ANIMATION_DELAY}}" || 0; 
        const el = root.querySelector('[class*="container"], [class*="plate"], [class*="box"], [class*="bar"], [class*="panel"]') || root.children[0]; 
        if(el) el.style.transitionDelay = `${delay}s`; 
        container.style.transform = "{{ANIMATION_IDENTITY}}"; 

        if (tickerTrack) { 
            setTimeout(() => { 
                const trackWidth = tickerTrack.scrollWidth || 0; 
                const speedPxPerSec = (parseFloat("{{speed}}") || parseFloat("{{TICKER_SPEED}}") || 50); 
                if (speedPxPerSec > 0 && trackWidth > 0) { 
                    const durationInSeconds = trackWidth / speedPxPerSec; 
                    tickerTrack.style.animation = 'none'; 
                    void tickerTrack.offsetWidth; 
                    tickerTrack.style.animation = `ticker-scroll ${durationInSeconds}s linear infinite`; 
                } 
            }, 100); 
        } 
    }; 

    root.__slt_hide = () => {
        const el = root.querySelector('[class*="container"], [class*="plate"], [class*="box"], [class*="bar"], [class*="panel"]') || root.children[0];
        if(el) el.style.transitionDelay = '{{ANIMATION_OUT_DELAY}}s';
        if (typeof container !== 'undefined' && container) {
            container.style.transition = "all {{ANIMATION_OUT_DURATION}}s {{ANIMATION_OUT_EASE}} {{ANIMATION_OUT_DELAY}}s";
            container.style.transform = "{{ANIMATION_OUT_TRANSFORM}}";
        }
    };
})();

templates.css_template:
#{{ID}} .rep-container {
    position: absolute;
    top: 0;
    left: 0;
    width: var(--v-width, 90%);
    box-sizing: border-box;
    display: flex;
    font-family: '{{FONT_FAMILY}}', 'Roboto Condensed', sans-serif;
    box-shadow: 0 10px 30px rgba(0,0,0,0.5);
    min-height: 120px;
    opacity: 0;
    transform-origin: left center;
    transform: {{ANIMATION_IN_TRANSFORM}};
    transition: all {{ANIMATION_DURATION}}s {{ANIMATION_EASE}};
}
#{{ID}} .rep-left-panel {
    width: 150px;
    background: {{PRIMARY_COLOR}};
    color: white;
    display: flex;
    flex-direction: column;
    z-index: 2;
    border-right: 2px solid rgba(255,255,255,0.1);
}
#{{ID}} .rep-logo {
    flex: 1;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    padding: 10px;
    background: {{SECONDARY_COLOR}};
}
#{{ID}} .rep-logo img {
    max-width: var(--v-width, 90%);
    box-sizing: border-box;
    max-height: 60px;
    object-fit: contain;
    filter: drop-shadow(0 2px 4px rgba(0,0,0,0.5));
}
#{{ID}} .rep-clock {
    height: 40px;
    background: #000c24;
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 28px;
    font-weight: 700;
    letter-spacing: 1px;
}
#{{ID}} .rep-content-area {
    flex: 1;
    display: flex;
    flex-direction: column;
    overflow: hidden;
}
#{{ID}} .rep-top-bar {
    flex: 1;
    background: {{PRIMARY_BG}};
    color: {{TITLE_COLOR}};
    display: flex;
    align-items: center;
    padding: 0 30px;
    position: relative;
    overflow: hidden;
}
#{{ID}} .rep-title {
    font-size: {{TITLE_SIZE}}px;
    font-weight: {{TITLE_WEIGHT}};
    text-transform: {{TITLE_TRANSFORM}};
    white-space: pre-line;
    z-index: 2;
    letter-spacing: -0.5px;
}
#{{ID}} .rep-side-graphic {
    position: absolute;
    right: 0;
    top: 0;
    bottom: 0;
    width: 300px;
    background: url('{{SIDE_IMAGE}}') center/cover;
    opacity: 0.8;
}
#{{ID}} .rep-side-graphic::before {
    content: '';
    position: absolute;
    top: 0; left: 0; right: 0; bottom: 0;
    background: linear-gradient(to right, {{SECONDARY_COLOR}} 0%, transparent 100%);
}
#{{ID}} .rep-bottom-bar {
    height: 40px;
    background: {{PRIMARY_BG}};
    display: flex;
    align-items: center;
    position: relative;
    overflow: hidden;
}
#{{ID}} .ticker-track {
    display: flex;
    align-items: center;
    white-space: nowrap;
    animation: rep-scroll 25s linear infinite;
    padding-left: 100%;
}
#{{ID}} .ticker-item {
    color: {{TITLE_COLOR}};
    font-size: 24px;
    font-weight: 600;
    text-transform: uppercase;
    padding: 0 20px;
}
#{{ID}} .ticker-sep {
    width: 12px;
    height: 24px;
    background: {{BORDER_COLOR}};
    transform: skewX(-30deg);
    margin: 0 10px;
}
@keyframes rep-scroll { 0% { transform: translateX(0); } 100% { transform: translateX(-100%); } }

templates.js_template:
(() => {
    const root = document.getElementById("{{ID}}");
    const container = root.querySelector(".rep-container");
    const clockEl = root.querySelector(".rep-clock");
    const tickerTrack = root.querySelector(".ticker-track");
    let timer;
    const updateTime = () => {
        const now = new Date();
        const h = String(now.getHours());
        const m = String(now.getMinutes()).padStart(2, "0");
        if(clockEl) clockEl.textContent = h + ":" + m;
    };
    root.__slt_show = () => {
        const delay = parseFloat("{{ANIMATION_DELAY}}") || 0;
        const el = root.querySelector("[class*=\"container\"], [class*=\"plate\"], [class*=\"box\"], [class*=\"bar\"], [class*=\"panel\"]") || root.children[0];
        if(el) el.style.transitionDelay = delay + "s";
        if(container) {
            void container.offsetWidth;
            container.style.opacity = "1";
            container.style.transform = "{{ANIMATION_IDENTITY}}";
        }
        updateTime();
        timer = setInterval(updateTime, 1000);
    };
    root.__slt_hide = () => {
        const el = root.querySelector("[class*=\"container\"], [class*=\"plate\"], [class*=\"box\"], [class*=\"bar\"], [class*=\"panel\"]") || root.children[0];
        if(el) el.style.transitionDelay = "{{ANIMATION_OUT_DELAY}}s";
        if (typeof container !== "undefined" && container) {
            container.style.transition = "all {{ANIMATION_OUT_DURATION}}s {{ANIMATION_OUT_EASE}} {{ANIMATION_OUT_DELAY}}s";
            container.style.opacity = "0";
            container.style.transform = "{{ANIMATION_OUT_TRANSFORM}}";
        }
        if (typeof timer !== "undefined") clearInterval(timer);
    };
})();

